Action.Str:
var contenu = global('RZ_JSON').trim();
var j = JSON.parse(contenu);
setGlobal('RZtask', j.task.trim());
setGlobal('RZparam', j.param.trim());

var raw = global('RZ_MENU_JSON') || '';
if (!raw.trim()) {
    flash('RZ_MENU_JSON vide');
} else {
    var j = JSON.parse(raw.trim());
    var trame = '$' + j.cat + ':' + j['var'] + ':' + j.prop + ':' + j.inst + ':' + j.val + '#';
    setGlobal('RZvpivOut', trame);
    writeFile('/sdcard/Tasker/RobotRZ/vpiv_out.txt', trame, false);
}

var raw = global('RZ_GLOBAL') || '{}';
var g = {};
try { g = JSON.parse(raw); } catch(e) { g = {}; }
var MODES  = {0:'ARRET',1:'VEILLE',2:'FIXE',3:'DEPLACEMENT',4:'AUTONOME',5:'ERREUR'};
var PTGE   = {0:'Ecran',1:'Vocal',2:'Manette',3:'Laisse',4:'Laisse+Vocal'};
var modeVal = g.CfgS ? (g.CfgS.modeRZ  !== undefined ? g.CfgS.modeRZ  : '?') : '?';
var ptgeVal = g.CfgS ? (g.CfgS.typePtge !== undefined ? g.CfgS.typePtge : '?') : '?';
var reseau  = g.CfgS ? (g.CfgS.typeReseau || '?') : '?';
setGlobal('RZetatMode',     MODES[modeVal] || ('Mode '+modeVal));
setGlobal('RZetatPtge',     PTGE[ptgeVal]  || ('Ptge '+ptgeVal));
setGlobal('RZetatReseau',   reseau);
setGlobal('RZetatIpSE',     (g.Sys && g.Sys.ipSE) ? g.Sys.ipSE : '192.168.1.12');
var ipSP = '?';
if      (reseau==='WifiInternetBox') ipSP='192.168.1.40 (local)';
else if (reseau==='Wifi4KSP')        ipSP='DuckDNS (4G SP)';
else if (reseau==='WifiSPSsI')       ipSP='SP Smart local';
else if (reseau==='4K')              ipSP='DuckDNS (SIM SE)';
setGlobal('RZetatIpSP', ipSP);
var CTX = {
    'WifiInternetBox':'Wi-Fi box maison - SP RPI local',
    'Wifi4KSP':       'Wi-Fi partage SP - SP RPI DuckDNS',
    'WifiSPSsI':      'Wi-Fi SP sans internet - SP Smart local',
    '4K':             'SIM SE - SP RPI via DuckDNS'
};
setGlobal('RZetatCtxReseau', CTX[reseau] || reseau);
var d = new Date();
setGlobal('RZetatTs', d.getHours()+':'+('0'+d.getMinutes()).slice(-2)+':'+('0'+d.getSeconds()).slice(-2));
performTask('RZ_EtatMajScene', 5);
performTask('RZ_EtatRefresh', 5);

var task = global('RZappliTask');
var nom = global('RZappliActive');
if (!task || task === '') {
    var map = {'Zoom':'RZ_Zoom','Maps':'RZ_Maps'};
    task = map[nom] || '';
    if (task) { setGlobal('RZappliTask', task); }
}
flash('AppStop: task=' + task + ' nom=' + nom);

var modeCam = global('RZmodeCam') || 'off';
if (modeCam === 'stream' || modeCam === 'snapshot') {
    setGlobal('RZtorchMode', 'webcam');
} else {
    setGlobal('RZtorchMode', 'termux');
}

var btn = global('RZmenuBtn') || '';
var modes = {
    'btn_veille':      '1',
    'btn_fixe':        '2',
    'btn_deplacement': '3',
    'btn_arret':       '0'
};var val = modes[btn] || '1';var json ='{"cat":"V","var":"CfgS","prop":"modeRZ","inst":"*","val":"' + val + '"}';setGlobal('RZmenuCmdJson', json);

// Table emoji
var expressions = {
    'sourire':   '😊',
    'neutre':    '😐',
    'colere':    '😠',
    'triste':    '😢',
    'surprise':  '😮',
    'peur':      '😨',
    'clin_oeil': '😉',
    'endormi':   '😴',
    'reflechi':  '🤔',
    'content':   '😄',
    'fatigue':   '😓',
    'curieux':   '🧐'
};
var EMOJI_DEFAUT = '😐';
var param = global('RZparam').trim().toLowerCase();
var emoji = expressions[param] || EMOJI_DEFAUT;
setGlobal('RZemoji', emoji);
setGlobal('RZemoji_defaut', EMOJI_DEFAUT);
var retour = (emoji !== EMOJI_DEFAUT) ? '1' : '0';
setGlobal('RZretourNeutre', retour);

var btn = global('RZmenuBtn') || '';
var applis = {
    'btn_cam':   {cat:'V', var:'CamSE',   prop:'modeCam', inst:'rear'},
    'btn_torch': {cat:'V', var:'TorchSE', prop:'active',  inst:'*'},
    'btn_zoom':  {cat:'A', var:'Appli',   prop:'Zoom',    inst:'*'},
    'btn_maps':  {cat:'A', var:'Appli',   prop:'Maps',    inst:'*'}
};
var cmd = applis[btn];
if (cmd) {
    var etatKey = 'RZetat_' + btn;
    var etat = global(etatKey) || 'off';
    var val;
    if (btn === 'btn_cam') {
        val = (etat === 'stream') ? 'off' : 'stream';
    } else {
        val = (etat === 'On') ? 'Off' : 'On';
    }
    var json = '{"cat":"' + cmd.cat + '","var":"' + cmd.var + '","prop":"' + cmd.prop + '","inst":"' + cmd.inst + '","val":"' + val + '"}';
    setGlobal('RZmenuCmdJson', json);
} else {
    setGlobal('RZmenuCmdJson', '');
}

var raw = global('RZ_GLOBAL') || '{}';
var g = {};
try { g = JSON.parse(raw); } catch(e) { g = {}; }
var MODES  = {0:'ARRET',1:'VEILLE',2:'FIXE',3:'DEPLACEMENT',4:'AUTONOME',5:'ERREUR'};
var PTGE   = {0:'Ecran',1:'Vocal',2:'Manette',3:'Laisse',4:'Laisse+Vocal'};
var modeVal = g.CfgS ? (g.CfgS.modeRZ  !== undefined ? g.CfgS.modeRZ  : '?') : '?';
var ptgeVal = g.CfgS ? (g.CfgS.typePtge !== undefined ? g.CfgS.typePtge : '?') : '?';
var reseau  = g.CfgS ? (g.CfgS.typeReseau || '?') : '?';
setGlobal('RZetatMode',     MODES[modeVal] || ('Mode '+modeVal));
setGlobal('RZetatPtge',     PTGE[ptgeVal]  || ('Ptge '+ptgeVal));
setGlobal('RZetatReseau',   reseau);
setGlobal('RZetatIpSE',     (g.Sys && g.Sys.ipSE) ? g.Sys.ipSE : '192.168.1.12');
var ipSP = '?';
if      (reseau==='WifiInternetBox') ipSP='192.168.1.40 (local)';
else if (reseau==='Wifi4KSP')        ipSP='DuckDNS (4G SP)';
else if (reseau==='WifiSPSsI')       ipSP='SP Smart local';
else if (reseau==='4K')              ipSP='DuckDNS (SIM SE)';
setGlobal('RZetatIpSP', ipSP);
var CTX = {
    'WifiInternetBox':'Wi-Fi box maison - SP RPI local',
    'Wifi4KSP':       'Wi-Fi partage SP - SP RPI DuckDNS',
    'WifiSPSsI':      'Wi-Fi SP sans internet - SP Smart local',
    '4K':             'SIM SE - SP RPI via DuckDNS'
};
setGlobal('RZetatCtxReseau', CTX[reseau] || reseau);
performTask('RZ_EtatMajScene', 5);
performTask('RZ_EtatRefresh', 5);
